cssRequirements.css:
@layer priority1 {
  .basex-checkbox-indicator {
    opacity: 1;
    transform: scale(1);
    transition: opacity 100ms ease-out, transform 100ms ease-out;
  }
  .basex-checkbox-indicator[data-starting-style],
  .basex-checkbox-indicator[data-ending-style] {
    opacity: 0;
    transform: scale(0.5);
  }
}
